module top_module( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;
  wire   xor_result, n2, n3, n4;

  // Logic for sum (S)
  assign xor_result = A ^ B; // xor_result = A XOR B
  assign n2 = xor_result ^ Ci; // S = (A XOR B) XOR Ci
  assign S = n2;

  // Logic for carry out (Co)
  assign n3 = A & B; // n3 = A AND B
  assign n4 = xor_result & Ci; // n4 = (A XOR B) AND Ci
  assign Co = n3 | n4; // Co = (A AND B) OR ((A XOR B) AND Ci)
endmodule
